const assert = require("node:assert/strict");
const fs = require("node:fs");
const path = require("node:path");
const test = require("node:test");
const vm = require("node:vm");

const STORAGE_KEY = "pocketledger.expenses.v1";
const html = fs.readFileSync(path.join(__dirname, "..", "index.html"), "utf8");
const script = html.match(/<script>([\s\S]*)<\/script>/)[1];

test("category filter narrows the rendered expense list", function () {
  const app = bootApp([
    expense({ id: "groceries-current", amountCents: 1250, category: "Groceries", date: currentMonthDate(3) }),
    expense({ id: "bills-current", amountCents: 4300, category: "Bills", date: currentMonthDate(4) }),
    expense({ id: "groceries-older", amountCents: 875, category: "Groceries", date: previousMonthDate(14) })
  ]);

  const filter = app.elements.categoryFilter;
  filter.value = "Groceries";
  filter.dispatchEvent({ type: "change" });

  const rows = expenseRows(app.elements.expenseList);
  assert.deepEqual(
    rows.map(function (row) {
      return row.querySelector(".category").textContent;
    }),
    ["Groceries", "Groceries"]
  );
  assert.equal(app.elements.expenseCount.textContent, "2 expenses recorded");
});

test("current month category totals group by category and ignore older expenses", function () {
  const app = bootApp([
    expense({ id: "groceries-1", amountCents: 1000, category: "Groceries", date: currentMonthDate(2) }),
    expense({ id: "groceries-2", amountCents: 500, category: "Groceries", date: currentMonthDate(7) }),
    expense({ id: "bills-1", amountCents: 2000, category: "Bills", date: currentMonthDate(9) }),
    expense({ id: "old-groceries", amountCents: 9999, category: "Groceries", date: previousMonthDate(11) })
  ]);

  const text = app.elements.categoryMonthlyTotals.textContent;
  assert.match(text, /Groceries/);
  assert.match(text, /Bills/);
  assert.match(text, /15[,.]00/);
  assert.match(text, /20[,.]00/);
  assert.doesNotMatch(text, /99[,.]99/);
});

test("CSV export downloads all expenses regardless of the active filter", function () {
  const app = bootApp([
    expense({
      id: "groceries-current",
      amountCents: 1250,
      category: "Groceries",
      date: "2026-07-03",
      note: "Milk, eggs"
    }),
    expense({
      id: "bills-current",
      amountCents: 4300,
      category: "Bills",
      date: "2026-07-04",
      note: "Power \"summer\""
    })
  ]);

  app.elements.categoryFilter.value = "Groceries";
  app.elements.categoryFilter.dispatchEvent({ type: "change" });
  app.elements.exportCsvButton.dispatchEvent({ type: "click" });

  assert.equal(app.downloads.length, 1);
  assert.equal(app.downloads[0].download, "pocketledger-expenses.csv");
  assert.equal(app.downloads[0].blob.type, "text/csv;charset=utf-8");
  assert.equal(app.downloads[0].blob.text, [
    "Date,Category,Note,Amount EUR",
    "2026-07-04,Bills,\"Power \"\"summer\"\"\",43.00",
    "2026-07-03,Groceries,\"Milk, eggs\",12.50"
  ].join("\r\n"));
});

function bootApp(seedExpenses) {
  const storage = new Map([[STORAGE_KEY, JSON.stringify(seedExpenses)]]);
  const elements = createElements();
  const downloads = [];
  const blobs = new Map();
  let nextBlobId = 1;

  vm.runInNewContext(script, {
    Array,
    Blob: class FakeBlob {
      constructor(parts, options) {
        this.text = parts.map(String).join("");
        this.type = options && options.type ? options.type : "";
      }
    },
    Date,
    Intl,
    JSON,
    Math,
    Number,
    RegExp,
    String,
    console,
    document: {
      createElement: function (tagName) {
        return new FakeElement(tagName, "", downloads, blobs);
      },
      getElementById: function (id) {
        return elements[id] || null;
      },
      body: new FakeElement("body", "", downloads, blobs)
    },
    URL: {
      createObjectURL: function (blob) {
        const url = "blob:fake-" + nextBlobId++;
        blobs.set(url, blob);
        return url;
      },
      revokeObjectURL: function (url) {
        blobs.delete(url);
      }
    },
    localStorage: {
      getItem: function (key) {
        return storage.has(key) ? storage.get(key) : null;
      },
      setItem: function (key, value) {
        storage.set(key, String(value));
      }
    },
    window: {}
  });

  return { downloads, elements, storage };
}

function createElements() {
  return {
    allTimeTotal: new FakeElement("strong"),
    amount: new FakeElement("input"),
    category: new FakeElement("input"),
    categoryFilter: new FakeElement("select"),
    categoryMonthlyTotals: new FakeElement("div"),
    date: new FakeElement("input"),
    exportCsvButton: new FakeElement("button"),
    expenseCount: new FakeElement("span"),
    expenseForm: new FakeElement("form"),
    expenseList: new FakeElement("ul"),
    expenseTemplate: new FakeTemplateElement(),
    monthTotal: new FakeElement("strong"),
    note: new FakeElement("input"),
    status: new FakeElement("p")
  };
}

function expense(overrides) {
  return Object.assign({
    amountCents: 100,
    category: "General",
    createdAt: "2026-01-01T00:00:00.000Z",
    date: currentMonthDate(1),
    id: "expense-id",
    note: ""
  }, overrides);
}

function expenseRows(list) {
  return list.children.filter(function (child) {
    return child.className.split(/\s+/).includes("expense-item");
  });
}

function currentMonthDate(day) {
  const now = new Date();
  return dateValue(now.getFullYear(), now.getMonth(), day);
}

function previousMonthDate(day) {
  const now = new Date();
  return dateValue(now.getFullYear(), now.getMonth() - 1, day);
}

function dateValue(year, zeroBasedMonth, day) {
  const date = new Date(year, zeroBasedMonth, day);
  return [
    date.getFullYear(),
    String(date.getMonth() + 1).padStart(2, "0"),
    String(date.getDate()).padStart(2, "0")
  ].join("-");
}

class FakeElement {
  constructor(tagName, className, downloads, blobs) {
    this.tagName = tagName.toUpperCase();
    this.attributes = {};
    this.children = [];
    this.className = className || "";
    this.dataset = {};
    this.download = "";
    this.eventListeners = {};
    this.href = "";
    this.id = "";
    this.parentNode = null;
    this.value = "";
    this.validationMessage = "";
    this.downloads = downloads || [];
    this.blobs = blobs || new Map();
    this._innerHTML = "";
    this._textContent = "";
    this.classList = {
      toggle: (name, force) => {
        const classes = this.className ? this.className.split(/\s+/) : [];
        const next = new Set(classes.filter(Boolean));
        const shouldAdd = force === undefined ? !next.has(name) : Boolean(force);

        if (shouldAdd) {
          next.add(name);
        } else {
          next.delete(name);
        }

        this.className = Array.from(next).join(" ");
        return shouldAdd;
      }
    };
  }

  get firstElementChild() {
    return this.children[0] || null;
  }

  get innerHTML() {
    return this._innerHTML;
  }

  set innerHTML(value) {
    this.children = [];
    this._innerHTML = String(value);
    this._textContent = String(value).replace(/<[^>]*>/g, "");
  }

  get textContent() {
    return this._textContent + this.children.map(function (child) {
      return child.textContent;
    }).join("");
  }

  set textContent(value) {
    this.children = [];
    this._innerHTML = "";
    this._textContent = String(value);
  }

  addEventListener(type, listener) {
    if (!this.eventListeners[type]) {
      this.eventListeners[type] = [];
    }

    this.eventListeners[type].push(listener);
  }

  appendChild(child) {
    child.parentNode = this;
    this.children.push(child);
    return child;
  }

  cloneNode(deep) {
    const copy = new FakeElement(this.tagName.toLowerCase(), this.className, this.downloads, this.blobs);
    copy.attributes = Object.assign({}, this.attributes);
    copy.dataset = Object.assign({}, this.dataset);
    copy.id = this.id;
    copy.value = this.value;
    copy._innerHTML = this._innerHTML;
    copy._textContent = this._textContent;

    if (deep) {
      this.children.forEach(function (child) {
        copy.appendChild(child.cloneNode(true));
      });
    }

    return copy;
  }

  closest(selector) {
    let current = this;
    while (current) {
      if (current.matches(selector)) {
        return current;
      }

      current = current.parentNode;
    }

    return null;
  }

  dispatchEvent(event) {
    const nextEvent = Object.assign({
      preventDefault: function () {},
      target: this
    }, event);
    (this.eventListeners[nextEvent.type] || []).forEach(function (listener) {
      listener(nextEvent);
    });
  }

  focus() {}

  click() {
    if (this.tagName === "A" && this.href) {
      this.downloads.push({
        blob: this.blobs.get(this.href),
        download: this.download,
        href: this.href
      });
    }

    this.dispatchEvent({ type: "click" });
  }

  matches(selector) {
    if (selector.startsWith(".")) {
      return this.className.split(/\s+/).includes(selector.slice(1));
    }

    return this.tagName.toLowerCase() === selector.toLowerCase();
  }

  querySelector(selector) {
    for (const child of this.children) {
      if (child.matches(selector)) {
        return child;
      }

      const match = child.querySelector(selector);
      if (match) {
        return match;
      }
    }

    return null;
  }

  reportValidity() {
    return !this.validationMessage;
  }

  reset() {
    this.children.forEach(function (child) {
      child.value = "";
    });
  }

  setAttribute(name, value) {
    this.attributes[name] = String(value);
  }

  setCustomValidity(message) {
    this.validationMessage = message;
  }
}

class FakeTemplateElement extends FakeElement {
  constructor() {
    super("template");
    this.content = new FakeElement("fragment");

    const item = new FakeElement("li", "expense-item");
    item.appendChild(new FakeElement("time"));
    item.appendChild(new FakeElement("span", "category"));
    item.appendChild(new FakeElement("span", "expense-note"));
    item.appendChild(new FakeElement("span", "amount"));
    item.appendChild(new FakeElement("button", "delete-button"));
    this.content.appendChild(item);
  }
}

